      <text x="182" y="100" fill="#52525b" font-size="26" text-anchor="middle">&#8594;</text>
      <rect x="195" y="60" width="150" height="70" rx="8" fill="#1c1c1f" stroke="#38bdf8" stroke-width="1.5"/>
